#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
typedef unsigned long long uLL;
const int Mod=2520;int s[25],len,ix[Mod+10],q;long long dp[25][Mod+10][55];inline void Init(){rep(1,Mod,i)if(Mod%i==0)ix[i]=++q;}
inline int gcd(int x,int y){return y?gcd(y,x%y):x;}inline int lcm(int x,int y){return x/gcd(x,y)*y;}
inline uLL dfs(int p,int r,int l,int m)
{
	if(!p)return r%l==0;if(!m&&~dp[p][r][ix[l]])return dp[p][r][ix[l]];
	uLL as=0;int mx=m==1?s[p]:9;rep(0,mx,i)
	{
		int nr=(r*10+i)%Mod,nl=l;if(i)nl=lcm(nl,i);
		as+=dfs(p-1,nr,nl,m&&i==mx);
	}
	if(!m)dp[p][r][ix[l]]=as;return as;
}
inline uLL C(uLL k){len=0;while(k)s[++len]=k%10,k/=10;return dfs(len,0,1,1);}
inline void S(){uLL l,r;scanf("%lld%lld",&l,&r);printf("%lld\n",(C(r)-C(l-1)));}
int main(){Init();memset(dp,-1,sizeof(dp));int T;scanf("%d",&T);while(T--)S();return 0;}
